import { isValidEmail } from '/tmp/clean-code';

it('should handle edge cases in email validation', () => {
  // Multiple @ symbols
  expect(isValidEmail('user@@example.com')).toBe(false);

  // Missing domain extension
  expect(isValidEmail('user@example')).toBe(false);

  // Spaces in email
  expect(isValidEmail('user name@example.com')).toBe(false);

  // Special characters that should be valid
  expect(isValidEmail('user+tag@example.com')).toBe(true);
  expect(isValidEmail('user.name@example.com')).toBe(true);

  // Extremely long email
  const longEmail = 'a'.repeat(64) + '@' + 'b'.repeat(63) + '.com';
  expect(isValidEmail(longEmail)).toBe(true);
});

import { sanitizeInput } from '/tmp/clean-code';

it('should handle edge cases in input sanitization', () => {
  // Multiple special characters
  expect(sanitizeInput('<<>>""\'\''))
    .toBe('&lt;&lt;&gt;&gt;&quot;&quot;&#039;&#039;');

  // Mixed content
  expect(sanitizeInput('Hello <b>World</b>!'))
    .toBe('Hello &lt;b&gt;World&lt;/b&gt;!');

  // Already encoded content (double encoding)
  expect(sanitizeInput('&lt;script&gt;'))
    .toBe('&amp;lt;script&amp;gt;');

  // Very long string performance
  const longInput = '<script>'.repeat(1000);
  const result = sanitizeInput(longInput);
  expect(result).toBe('&lt;script&gt;'.repeat(1000));
});

